'use strict';

// Auto-nudge sidecar — on-disk apply mechanism for the IL closed loop.
//
// When runFullCycle's verdict is 'promote', the orchestrator writes a
// sidecar file alongside the specialist spec:
//
//   lib/specialists/<id>.js              <- human-owned spec file
//   lib/specialists/<id>.auto-nudge.js   <- AUTO-GENERATED sidecar
//
// The specialist bundle loader (one-line addition near the bottom of the
// spec file) reads the sidecar if present and concatenates its export
// onto the systemPrompt at load time.  Humans never edit the sidecar;
// runFullCycle owns it.  Clear semantics: delete the sidecar to revert.
//
// Sidecar file shape:
//   // AUTO-GENERATED by runFullCycle. Do not edit by hand.
//   // Generated: 2026-05-13T22:18:00.000Z
//   // Source proposal: autoprop-40d419b1321a
//   // Cycle: cycle-7a8b9c0d
//   // Target version: 0.3.0
//   module.exports = `
//   ...nudge text...
//   `;
//
// Atomic-write contract: writeSidecar writes to a `.tmp.<random>` file
// then `fs.renameSync` to the final path.  This avoids a partial-file
// state if the process dies mid-write while a parallel cycle is loading
// the bundle.

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const DEFAULT_SPECIALISTS_DIR = path.join(__dirname, '..', 'specialists');

function sidecarPath(specialistId, opts = {}) {
  const dir = opts.specialistsDir || DEFAULT_SPECIALISTS_DIR;
  return path.join(dir, `${specialistId}.auto-nudge.js`);
}

function specPath(specialistId, opts = {}) {
  const dir = opts.specialistsDir || DEFAULT_SPECIALISTS_DIR;
  return path.join(dir, `${specialistId}.js`);
}

function readSidecar(specialistId, opts = {}) {
  // Read + parse directly rather than going through require(): Node's
  // module cache is not reliably invalidated across atomic rename, so
  // tests that write/read in rapid succession saw stale content.  The
  // sidecar file shape is fixed (header comment + `module.exports = \`
  // …\`;`), so a small regex extract is sufficient and avoids the
  // caching surface entirely.
  const p = sidecarPath(specialistId, opts);
  if (!fs.existsSync(p)) return null;
  let raw;
  try {
    raw = fs.readFileSync(p, 'utf8');
  } catch (_) {
    return null;
  }
  const match = raw.match(/module\.exports\s*=\s*`([\s\S]*?)`\s*;/);
  if (!match) return null;
  // Reverse the escape pass writeSidecar applies (in opposite order).
  return match[1]
    .replace(/\\\$\{/g, '${')
    .replace(/\\`/g, '`')
    .replace(/\\\\/g, '\\');
}

function writeSidecar(specialistId, nudgeText, meta = {}, opts = {}) {
  const finalPath = sidecarPath(specialistId, opts);
  const dir = path.dirname(finalPath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

  // Escape backticks and ${...} interpolations in the nudge text so the
  // generated file is a syntactically valid template literal.
  const safeText = String(nudgeText || '')
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$\{/g, '\\${');

  const generatedAt = meta.generatedAt || new Date().toISOString();
  const header = [
    '// AUTO-GENERATED by runFullCycle. Do not edit by hand.',
    `// Generated: ${generatedAt}`,
    `// Source proposal: ${meta.proposalId || '(unknown)'}`,
    `// Cycle: ${meta.cycleId || '(unknown)'}`,
    `// Target version: ${meta.targetVersion || '(unknown)'}`,
    '',
    "'use strict';",
    '',
    'module.exports = `',
    safeText,
    '`;',
    '',
  ].join('\n');

  // Atomic write: temp file in same dir + rename.
  const tmpPath = finalPath + '.tmp.' + crypto.randomBytes(6).toString('hex');
  fs.writeFileSync(tmpPath, header, 'utf8');
  fs.renameSync(tmpPath, finalPath);

  // Invalidate the require cache so the next readSidecar / bundle load
  // sees the fresh content.
  try { delete require.cache[require.resolve(finalPath)]; } catch (_) {}

  return finalPath;
}

function clearSidecar(specialistId, opts = {}) {
  const p = sidecarPath(specialistId, opts);
  if (fs.existsSync(p)) {
    fs.unlinkSync(p);
    try { delete require.cache[require.resolve(p)]; } catch (_) {}
    return true;
  }
  return false;
}

function bumpMinor(versionString) {
  // semver-ish minor bump: M.m.p → M.(m+1).0.  Strict: throws on malformed.
  if (typeof versionString !== 'string') {
    throw new Error('bumpMinor: version must be a string');
  }
  const match = /^(\d+)\.(\d+)\.(\d+)$/.exec(versionString.trim());
  if (!match) {
    throw new Error(`bumpMinor: version "${versionString}" is not M.m.p`);
  }
  const [, major, minor] = match;
  return `${major}.${Number(minor) + 1}.0`;
}

function rewriteVersionInSpec(specFilePath, newVersion, opts = {}) {
  // Narrow surgical replace: only touch `const version = '...'`.  Throws
  // if the regex doesn't match exactly once — we refuse to silently
  // mutate a spec file with an unexpected shape.
  if (!fs.existsSync(specFilePath)) {
    throw new Error(`rewriteVersionInSpec: spec file not found at ${specFilePath}`);
  }
  const source = fs.readFileSync(specFilePath, 'utf8');
  const re = /const\s+version\s*=\s*(['"])([^'"]+)\1\s*;/g;
  const matches = source.match(re);
  if (!matches || matches.length !== 1) {
    throw new Error(`rewriteVersionInSpec: expected exactly one \`const version = '...'\` declaration in ${specFilePath}, found ${matches ? matches.length : 0}`);
  }
  const rewritten = source.replace(re, `const version = '${newVersion}';`);
  // Atomic write the spec file too, same temp-then-rename pattern.
  const tmpPath = specFilePath + '.tmp.' + crypto.randomBytes(6).toString('hex');
  fs.writeFileSync(tmpPath, rewritten, 'utf8');
  fs.renameSync(tmpPath, specFilePath);
  try { delete require.cache[require.resolve(specFilePath)]; } catch (_) {}
  return { previousVersion: matches[0], newVersion };
}

module.exports = {
  sidecarPath,
  specPath,
  readSidecar,
  writeSidecar,
  clearSidecar,
  bumpMinor,
  rewriteVersionInSpec,
};
